/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently focused on email settings; designed to accommodate
 * additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - 'immediate': sent as events occur
 * - 'daily-digest': batched into a daily summary
 * - 'weekly-digest': batched into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  categorySubscriptions: Record<NotificationType, boolean>;
}

/**
 * Full user notification preferences.
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Returns default email preferences with all categories enabled and immediate delivery.
 */
export function defaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categorySubscriptions: {
      'order:confirmation': true,
      'order:status-update': true,
      'user:welcome': true,
      'user:profile-updated': true,
    },
  };
}

parameters.new_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels:
 * email, SMS, and webhook. Each channel has independent enabled/subscription settings.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - 'immediate': sent as events occur
 * - 'daily-digest': batched into a daily summary
 * - 'weekly-digest': batched into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  categorySubscriptions: Record<NotificationType, boolean>;
}

/**
 * SMS-specific notification preferences.
 * SMS is always immediate — no frequency setting needed.
 */
export interface SmsPreferences {
  enabled: boolean;
  categorySubscriptions: Record<NotificationType, boolean>;
}

/**
 * Webhook-specific notification preferences.
 * Webhooks are always immediate — no frequency setting needed.
 */
export interface WebhookPreferences {
  enabled: boolean;
  categorySubscriptions: Record<NotificationType, boolean>;
}

/**
 * Full user notification preferences.
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Input for updating SMS preferences. All fields optional.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Input for updating webhook preferences. All fields optional.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Returns default email preferences with all categories enabled and immediate delivery.
 */
export function defaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    categorySubscriptions: {
      'order:confirmation': true,
      'order:status-update': true,
      'user:welcome': true,
      'user:profile-updated': true,
    },
  };
}

/**
 * Returns default SMS preferences with all categories enabled.
 */
export function defaultSmsPreferences(): SmsPreferences {
  return {
    enabled: true,
    categorySubscriptions: {
      'order:confirmation': true,
      'order:status-update': true,
      'user:welcome': true,
      'user:profile-updated': true,
    },
  };
}

/**
 * Returns default webhook preferences with all categories enabled.
 */
export function defaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: true,
    categorySubscriptions: {
      'order:confirmation': true,
      'order:status-update': true,
      'user:welcome': true,
      'user:profile-updated': true,
    },
  };
}

