/**
 * Update SMS preferences for a user. Creates defaults first if none exist.
 */
updateSmsPreferences(
  userId: string,
  input: UpdateSmsPreferencesInput,
): UserNotificationPreferences {
  const prefs = this.getOrCreatePreferences(userId);

  const updatedSms = { ...prefs.sms };

  if (input.enabled !== undefined) {
    updatedSms.enabled = input.enabled;
  }
  if (input.categorySubscriptions) {
    updatedSms.categorySubscriptions = {
      ...updatedSms.categorySubscriptions,
      ...input.categorySubscriptions,
    };
  }

  this.logger.info(`Updating SMS preferences for user ${userId}`);
  return this.preferencesRepository.update(prefs.id, {
    sms: updatedSms,
    updatedAt: new Date(),
  });
}

/**
 * Update webhook preferences for a user. Creates defaults first if none exist.
 */
updateWebhookPreferences(
  userId: string,
  input: UpdateWebhookPreferencesInput,
): UserNotificationPreferences {
  const prefs = this.getOrCreatePreferences(userId);

  const updatedWebhook = { ...prefs.webhook };

  if (input.enabled !== undefined) {
    updatedWebhook.enabled = input.enabled;
  }
  if (input.categorySubscriptions) {
    updatedWebhook.categorySubscriptions = {
      ...updatedWebhook.categorySubscriptions,
      ...input.categorySubscriptions,
    };
  }

  this.logger.info(`Updating webhook preferences for user ${userId}`);
  return this.preferencesRepository.update(prefs.id, {
    webhook: updatedWebhook,
    updatedAt: new Date(),
  });
}

/**
 * Check if a user should receive a notification of the given type via SMS.
 * Returns true if: SMS is enabled AND the specific category is subscribed.
 * If no preferences exist, defaults to true (opt-out model).
 */
shouldSendSms(userId: string, notificationType: NotificationType): boolean {
  const prefs = this.preferencesRepository.findByUserId(userId);
  if (!prefs) {
    return true;
  }
  if (!prefs.sms.enabled) {
    return false;
  }
  return prefs.sms.categorySubscriptions[notificationType] !== false;
}

/**
 * Check if a user should receive a notification of the given type via webhook.
 * Returns true if: webhook is enabled AND the specific category is subscribed.
 * If no preferences exist, defaults to true (opt-out model).
 */
shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
  const prefs = this.preferencesRepository.findByUserId(userId);
  if (!prefs) {
    return true;
  }
  if (!prefs.webhook.enabled) {
    return false;
  }
  return prefs.webhook.categorySubscriptions[notificationType] !== false;
}

