describe('NotificationService with multi-channel preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    const repo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repo);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should suppress SMS notification when SMS is disabled', async () => {
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateSmsPreferences('user-1', { enabled: false });

    const result = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'user-1',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed',
      channel: 'sms',
      priority: 'normal',
    });

    expect(result.success).toBe(false);
    expect(result.error).toBe('Suppressed by user preferences');
  });

  it('should suppress webhook notification when webhook is disabled', async () => {
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateWebhookPreferences('user-1', { enabled: false });

    const result = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'user-1',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed',
      channel: 'webhook',
      priority: 'normal',
    });

    expect(result.success).toBe(false);
    expect(result.error).toBe('Suppressed by user preferences');
  });

  it('should suppress SMS when category is unsubscribed but allow email', async () => {
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateSmsPreferences('user-1', {
      categorySubscriptions: { 'order:confirmation': false },
    });

    const smsResult = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'user-1',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed',
      channel: 'sms',
      priority: 'normal',
    });

    const emailResult = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'user-1',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed',
      channel: 'email',
      priority: 'normal',
    });

    expect(smsResult.success).toBe(false);
    expect(smsResult.error).toBe('Suppressed by user preferences');
    // Email should not be suppressed (no adapter, but not suppressed by prefs)
    expect(emailResult.error).not.toBe('Suppressed by user preferences');
  });

  it('should allow SMS when no preferences exist (opt-out model)', async () => {
    const result = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'unknown-user',
      subject: 'Order Confirmation',
      body: 'Your order is confirmed',
      channel: 'sms',
      priority: 'normal',
    });

    // Not suppressed by preferences — fails only because no adapter
    expect(result.error).toBe('No adapter for channel: sms');
  });

  it('should independently control each channel', async () => {
    preferencesService.getOrCreatePreferences('user-1');
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    preferencesService.updateSmsPreferences('user-1', { enabled: true });
    preferencesService.updateWebhookPreferences('user-1', { enabled: false });

    const emailResult = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'user-1',
      subject: 'Test',
      body: 'Test',
      channel: 'email',
      priority: 'normal',
    });

    const smsResult = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'user-1',
      subject: 'Test',
      body: 'Test',
      channel: 'sms',
      priority: 'normal',
    });

    const webhookResult = await notificationService.send({
      type: 'order:confirmation',
      recipient: 'user-1',
      subject: 'Test',
      body: 'Test',
      channel: 'webhook',
      priority: 'normal',
    });

    expect(emailResult.error).toBe('Suppressed by user preferences');
    expect(smsResult.error).toBe('No adapter for channel: sms'); // Not suppressed, just no adapter
    expect(webhookResult.error).toBe('Suppressed by user preferences');
  });
});

